function DemoSection() {
  const [models, setModels] = useState<Model[]>([]);
  const [selectedModel, setSelectedModel] = useState("");
  const [prompt, setPrompt] = useState("");
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<{
    model: string;
    price_paid_usdt: number;
    usage: { prompt_tokens: number; completion_tokens: number };
  } | null>(null);
  const [payments, setPayments] = useState<PaymentLog[]>([]);
  const paymentId = useRef(0);

  useEffect(() => {
    fetch(`${GATEWAY_URL}/models`)
      .then((r) => r.json())
      .then((d) => {
        setModels(d.models);
        if (d.models.length) setSelectedModel(d.models[0].id);
      })
      .catch(() => {});
  }, []);

  const sendRequest = async () => {
    if (!prompt.trim() || !selectedModel) return;
    setLoading(true);
    setResponse("");
    setResult(null);

    const model = models.find((m) => m.id === selectedModel);
    if (!model) return;

    try {
      const res = await fetch(`${GATEWAY_URL}${model.endpoint}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [{ role: "user", content: prompt }],
          max_tokens: 512,
        }),
      });

      if (res.status === 402) {
        setResponse(
          "402 Payment Required — this endpoint needs an x402 payment header. " +
            "In production, the agent's WDK wallet signs an EIP-3009 authorization and retries automatically."
        );
        setResult(null);
      } else if (res.ok) {
        const data = await res.json();
        setResponse(data.content);
        setResult(data);
        const newPayment: PaymentLog = {
          id: ++paymentId.current,
          model: data.model,
          price: data.price_paid_usdt,
          tokens:
            (data.usage?.prompt_tokens || 0) +
            (data.usage?.completion_tokens || 0),
          ts: Date.now(),
        };
        setPayments((prev) => [newPayment, ...prev].slice(0, 20));
      } else {
        const text = await res.text();
        setResponse(`Error ${res.status}: ${text}`);
      }
    } catch (e: unknown) {
      setResponse(`Connection error: ${e instanceof Error ? e.message : "Unknown"}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <section id="demo" className="px-6 sm:px-12 py-16 border-t border-[#f0f0f0] grid-pattern">
      <div className="text-center">
        <span className="text-[11px] font-semibold uppercase tracking-wider text-emerald-600">
          Interactive
        </span>
        <h2 className="mt-2 font-display text-[32px] text-[#111]">
          Try the Gateway
        </h2>
        <p className="mt-2 text-[14px] text-[#888]">
          Send a request to see the x402 payment flow in action.
          Without a wallet, you'll see the 402 response.
        </p>
      </div>

      <div className="mt-8 grid gap-6 sm:grid-cols-5">
        {/* Input panel */}
        <div className="sm:col-span-3 space-y-4">
          <div>
            <label className="text-[11px] font-semibold uppercase tracking-wider text-[#999]">
              Model
            </label>
            <select
              value={selectedModel}
              onChange={(e) => setSelectedModel(e.target.value)}
              className="mt-1 w-full rounded-lg border-[1.5px] border-[#e8e8e8] bg-[#fafafa] px-3 py-2.5 text-[14px] outline-none focus:border-[#111] focus:bg-white transition-colors"
            >
              {models.map((m) => (
                <option key={m.id} value={m.id}>
                  {m.label} — ${m.price_usdt.toFixed(4)}/call
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="text-[11px] font-semibold uppercase tracking-wider text-[#999]">
              Prompt
            </label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Ask anything..."
              rows={3}
              className="mt-1 w-full rounded-lg border-[1.5px] border-[#e8e8e8] bg-[#fafafa] px-3 py-2.5 text-[14px] outline-none focus:border-[#111] focus:bg-white transition-colors resize-none"
            />
          </div>

          <button
            onClick={sendRequest}
            disabled={loading || !prompt.trim()}
            className="inline-flex items-center gap-2 rounded-full bg-[#111] px-6 py-2.5 text-[14px] font-medium text-white transition-colors hover:bg-[#333] disabled:opacity-30"
          >
            {loading ? (
              <>
                <span className="inline-block h-3 w-3 animate-spin rounded-full border-2 border-current border-t-transparent" />
                Processing...
              </>
            ) : (
              <>
                Send Request
                <svg
                  className="h-4 w-4"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M14 5l7 7m0 0l-7 7m7-7H3"
                  />
                </svg>
              </>
            )}
          </button>

          {/* Response */}
          {response && (
            <div className="mt-4 rounded-xl border border-[#e8e8e8] bg-white p-5 animate-fade-in">
              {result && (
                <div className="mb-4 flex flex-wrap gap-3">
                  <span className="rounded-full bg-emerald-50 px-2.5 py-1 text-[11px] font-semibold text-emerald-600 border border-emerald-200">
                    Paid ${result.price_paid_usdt}
                  </span>
                  <span className="rounded-full bg-blue-50 px-2.5 py-1 text-[11px] font-semibold text-blue-600 border border-blue-200">
                    {result.usage?.prompt_tokens || 0} + {result.usage?.completion_tokens || 0} tokens
                  </span>
                  <span className="rounded-full bg-[#fafafa] px-2.5 py-1 text-[11px] font-semibold text-[#888] border border-[#e8e8e8]">
                    {result.model}
                  </span>
                </div>
              )}
              <div className="text-[14px] leading-relaxed text-[#333] whitespace-pre-wrap">
                {response}
              </div>
            </div>
          )}
        </div>

        {/* Payment feed */}
        <div className="sm:col-span-2">
          <div className="rounded-2xl border-[1.5px] border-[#e8e8e8] bg-white p-5">
            <div className="flex items-center gap-2 mb-4">
              <span className="h-2 w-2 rounded-full bg-emerald-400 animate-pulse-dot" />
              <span className="text-[13px] font-semibold text-[#111]">
                Payment Feed
              </span>
            </div>

            {payments.length === 0 ? (
              <div className="py-8 text-center text-[13px] text-[#bbb]">
                No payments yet.
                <br />
                Send a request to see payments appear.
              </div>
            ) : (
              <div className="space-y-3">
                {payments.map((p) => (
                  <div
                    key={p.id}
                    className="flex items-center justify-between rounded-lg border border-[#f0f0f0] bg-[#fafafa] px-3 py-2.5 animate-slide-in"
                  >
                    <div>
                      <div className="text-[12px] font-semibold text-[#111]">
                        {p.model.split("-").slice(0, 2).join(" ")}
                      </div>
                      <div className="text-[11px] text-[#999]">
                        {p.tokens} tokens
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="font-mono text-[13px] font-semibold text-emerald-600">
                        ${p.price}
                      </div>
                      <div className="text-[10px] text-[#bbb]">
                        {new Date(p.ts).toLocaleTimeString()}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}

